INSERT INTO `instructors` (`id`, `instructor_name`, `instructor_name_ja`, `instructor_slug`, `instructor_pic`, `instructor_designation`, `instructor_designation_ja`, `instructor_desc`, `instructor_desc_ja`, `status`) VALUES
(7, 'Aiko Nakamura', '中村愛子', 'aiko-nakamura', '/storage/photos/1/team-01.jpg', 'Behavioral Finance & Consumer Psychology', '行動ファイナンスと消費者心理学', '<p>Aiko brings over a decade of experience in financial behavior research and market psychology. She has led multiple cross-border educational initiatives, designed investment behavior modules for executive programs, and has mentored professionals across Asia. Known for her approachable teaching style, she blends theory with real-world insight, helping learners decode the emotions behind financial decision-making.</p>\n<h3>Experience</h3>\n<ul>\n<li>10+ years teaching and consulting in behavioral finance</li>\n<li>Designed strategic investor behavior frameworks used in training programs</li>\n<li>Featured speaker in several financial literacy forums across East Asia</li>\n<li>Led investor training workshops for financial institutions and fintech startups</li>\n</ul>\n\n', '<p>Aikoは、金融行動研究と市場心理学における十年以上の経験をもたらします。 彼女は複数の国境を越えた教育イニシアチブを主導し、エグゼクティブプログラムのための投資行動モジュールを設計し、アジアの専門家を指導してきました。 親しみやすい指導スタイルで知られる彼女は、理論と現実世界の洞察を融合させ、学習者が金融意思決定の背後にある感情を解読するのを助けます。</p>\n<h3>経験</h3>\n<ul>\n<li>行動ファイナンスにおける10年以上の教育とコンサルティング</li>\n<li>トレーニングプログラムで使用される戦略的投資家行動フレームワークを設計</li>\n<li>東アジアのいくつかの金融リテラシーフォーラムでスピーカーを特集</li>\n<li>金融機関やfintechスタートアップのためのLed投資家トレーニングワークショップ</li>\n</ul>', 'A'),
(8, 'David Rutherford', 'デヴィッド・ラザフォード', 'david-rutherford', '/storage/photos/1/team-04.jpg', 'Investment Strategy & Portfolio Management', '投資戦略-ポートフォリオマネジメント', '<p>David is a seasoned investment strategist with a strong foundation in traditional and modern finance techniques. With extensive experience leading international finance workshops, he’s known for simplifying complex models and helping learners build data-driven portfolios. His career includes advisory roles in fund management and private wealth, making his teaching both practical and visionary.</p>\n<h3>Experience</h3>\n<ul>\n<li>Guided over 5,000 learners globally in asset management courses</li>\n<li>Developed risk assessment tools used in portfolio planning seminars</li>\n<li>Experience includes global banking strategy panels and finance think-tanks</li>\n<li>Known for integrating global case studies into investment curriculum</li>\n</ul>', '<p>Davidは、伝統的および現代的な金融技術の強力な基盤を持つベテランの投資ストラテジストです。 国際的な金融ワークショップをリードする豊富な経験を持つ彼は、複雑なモデルを簡素化し、学習者がデータ駆動型のポートフォリオを構築するのを助 彼のキャリアには、ファンド管理と私的な富のアドバイザリーの役割が含まれており、実践的で先見の明のある教えをしています。</p>\n<h3>経験</h3>\n<ul>\n<li>資産管理コースでグローバルに5,000人以上の学習者を導いた</li>\n<li>ポートフォリオ計画セミナーで使用されるリスク評価ツールを開発</li>\n<li>経験には、グローバルバンキング戦略パネルと金融シンクタンクが含まれています</li>\n<li>グローバルなケーススタディを投資カリキュラムに統合することで知られています</li>\n</ul>', 'A'),
(9, 'Haruki Tanabe', '田辺春香', 'haruki-tanabe', '/storage/photos/1/team-05.jpg', 'Business Psychology & Leadership', 'ビジネス心理学とリーダーシップ', '<p>Leena specializes in leadership science and organizational behavior, with a passion for cultivating emotional intelligence in business. She’s worked closely with HR teams and leadership boards to shape transformation programs for top-tier companies. Her teaching style emphasizes mindfulness, ethical leadership, and team dynamics for long-term business impact.</p>\n<h3>Experience</h3>\n<ul>\n<li>Over 12 years of corporate coaching and leadership training experience</li>\n<li>Contributed to executive development programs across 3 continents</li>\n<li>Helped design culture-building blueprints for growing enterprises</li>\n<li>Recognized for her engaging sessions on negotiation and leadership trust</li>\n</ul>', '<p>Leenaは、ビジネスにおける感情的知性の育成に情熱を持って、リーダーシップ科学と組織行動を専門としています。 彼女は人事チームやリーダーシップボードと緊密に協力して、トップクラスの企業のための変革プログラムを形成しています。 彼女の指導スタイルは、長期的なビジネスへの影響のためのマインドフルネス、倫理的リーダーシップ、およびチームダイナミクスを強調しています。</p>\n<h3>経験</h3>\n<ul>\n<li>企業のコーチングとリーダーシップトレーニングの経験の12年以上</li>\n<li>3大陸のエグゼクティブ開発プログラムに貢献</li>\n<li>成長する企業のための文化構築の青写真を設計するのを助けました</li>\n<li>交渉とリーダーシップの信頼に関する彼女の魅力的なセッションのために認識</li>\n</ul>', 'A'),
(10, 'Emiko Tanake', '田中恵美子', 'emiko-tanake', '/storage/photos/1/team-06.jpg', 'AI in Finance & Tech Innovation', '金融と技術革新におけるAI', '<p>Kenji blends a tech-forward mindset with deep insights into financial systems. With a background in data analytics and emerging technologies, he has trained professionals to navigate the future of finance. His sessions explore automation, fintech disruptions, and the evolving role of AI in business.</p>\n<h3>Experience</h3>\n<ul>\n<li>Led digital transformation seminars for finance and consulting sectors</li>\n<li>Created simulation-based training tools used in innovation programs</li>\n<li>Experience spans over 30 bootcamps and AI-for-business workshops</li>\n<li>Focused on demystifying tech for non-tech professionals</li>\n</ul>', '<p>Kenjiは、テクノロジーフォワードの考え方と金融システムへの深い洞察を融合させています。 データ分析と新興技術の背景を持つ彼は、金融の未来をナビゲートするための専門家を訓練してきました。 彼のセッションでは、自動化、フィンテックの混乱、ビジネスにおけるAIの進化する役割について説明しています。</p>\n<h3>経験</h3>\n<ul>\n<li>金融-コンサルティング分野のデジタル変革セミナーを主導</li>\n<li>イノベーションプログラムで使用されるシミュレーションベースのトレーニングツールを作成</li>\n<li>経験は30以上のブートキャンプとAI-for-businessワークショップに及びます</li>\n<li>非技術専門家のための技術の謎を解くことに焦点を当てた</li>\n</ul>', 'A');

