INSERT INTO `products` (`id`, `title`, `title_jp`, `slug`, `summary`, `summary_jp`, `description`, `description_jp`, `meta_title`, `meta_description`, `meta_keyword`, `photo`, `stock`, `size`, `condition`, `status`, `price`, `price_jp`, `price_hk`, `discount`, `is_featured`, `extra_description`, `extra_description_jp`, `cat_id`, `child_cat_id`, `brand_id`, `duration`, `skill_level`, `skill_level_jp`, `lectures`, `language`, `language_jp`, `created_at`, `updated_at`) VALUES
(1, 'Foundations of Anime Anatomy: From Sketch to Structure', 'アニメ解剖学の基礎：スケッチから構造へ', 'foundations-of-anime-anatomy-from-sketch-to-structure', '', '', 'Unlock the essential foundations of anime character anatomy in this comprehensive course designed specifically for aspiring artists who want to create believable and dynamic characters. Anime anatomy blends realistic human proportions with stylized features, and this course will help you master that balance. You’ll start by breaking down the human body into simple, easy-to-understand shapes and gradually build up to more complex muscle groups and joint movements, all adapted for the anime aesthetic.\r\nThrough step-by-step lessons, you will learn how to structure the torso, limbs, and head in a way that allows for flexibility and expressiveness. You’ll practice drawing characters in various poses to understand weight, balance, and proportion, helping you avoid common pitfalls that make anime characters look stiff or awkward.\r\nWhether you dream of creating original characters, working for an animation studio, or simply improving your drawing skills, this course sets a strong technical foundation that will support your creative freedom and storytelling.', '信じられないとダイナミックな文字を作成したい意欲的なアーティストのために特別に設計されたこの包括的なコースでアニメキャラクターの解剖学の本質的な基礎のロックを解除します。 Anime anatomyは、現実的な人間のプロポーションと定型化された機能をブレンドしており、このコースはそのバランスを習得するのに役立ちます。 人間の体をシンプルでわかりやすい形に分解することから始め、徐々により複雑な筋肉群と関節の動きまで構築し、すべてアニメの美学に適応します。\r\nステップバイステップのレッスンを通して、あなたは柔軟性と表現力を可能にする方法で胴体、手足、頭を構造化する方法を学びます。 さまざまなポーズでキャラクターを描く練習をして、体重、バランス、比率を理解し、アニメキャラクターを硬く見せたりぎこちなく見せたりする一般的な落とし穴を避けるのに役立ちます。\r\nオリジナルキャラクターの作成、アニメーションスタジオでの作業、または単に描画スキルの向上を夢見ているかどうかにかかわらず、このコースはあなたの創造的な自由とストーリーテリングをサポートする強力な技術基盤を設定します。', 'Foundations of Anime Anatomy: Master Sketching & Structure for Characters', 'Learn anime anatomy fundamentals! Master sketching, proportions, and structure to create dynamic anime characters from scratch. Perfect for beginners.', 'anime anatomy, character sketching, anime proportions, drawing tutorial', 'storage/photos/products/1.webp', 10000, '', '', 'active', 59.00, 9440.00, 472.00, 0.00, 0, '<ul>\r\n  <li>Simplify the human anatomy into manageable, stylized shapes tailored for anime</li>\r\n  <li>Draw characters with correct proportions that allow for movement and emotion</li>\r\n  <li>Construct dynamic poses that convey energy and personality</li>\r\n  <li>Identify and correct common anatomical mistakes to improve your drawings</li>\r\n  <li>Use anatomy knowledge to create believable character silhouettes</li>\r\n</ul>', '<ul>\r\n  <li>人間の解剖学をアニメに合わせた管理しやすい様式化された形に簡素化</li>\r\n  <li>動きと感情を可能にする正しい比率で文字を描く</li>\r\n  <li>エネルギーと個性を伝えるダイナミックなポーズを構築</li>\r\n  <li>あなたの図面を改善するために、一般的な解剖学的ミスを特定し、修正</li>\r\n  <li>解剖学の知識を使って信じられないキャラクターのシルエットを作成</li>\r\n</ul>', 1, 0, 0, 5, 'Core Studio', 'コアスタジオ', 10, 'English & Japanese', '英語＆日本語', NULL, NULL),
(2, 'Facial Expressions & Emotions in Anime Characters', 'アニメキャラクターの表情と感情', 'facial-expressions-and-emotions-in-anime-characters', '', '', 'Mastering facial expressions is key to making anime characters come alive with personality and emotion. In this course, you’ll dive deep into the anatomy of the face and learn how subtle changes to eyes, eyebrows, and mouths can dramatically change how your characters feel and react.\r\nUsing detailed examples and practice exercises, you’ll explore how to portray a wide spectrum of emotions—from joy and surprise to anger and sadness—with the unique stylization anime demands. You’ll learn how to exaggerate expressions without losing believability and how to balance the iconic large anime eyes with nuanced emotional cues.\r\nBy the end, you’ll be able to create characters whose expressions tell compelling stories, whether for manga, animation, or concept art. This course also covers how to maintain character consistency across multiple expressions and angles.', '表情をマスターすることは、アニメのキャラクターを個性と感情で生き生きとさせるための鍵です。 このコースでは、顔の解剖学的構造を深く掘り下げ、目、眉毛、口の微妙な変化がキャラクターの感情や反応を劇的に変えることができる方法を学びます。\r\n詳細な例と練習問題を使用して、喜びや驚きから怒りや悲しみまで、さまざまな感情を独特の様式化アニメの要求で表現する方法を探ります。 信憑性を失うことなく表現を誇張する方法と、象徴的な大きなアニメの目と微妙な感情的な手がかりのバランスをとる方法を学びます。\r\n最終的には、マンガ、アニメーション、コンセプトアートなど、魅力的なストーリーを表現するキャラクターを作成することができます。 このコースでは、複数の表現や角度にわたって文字の一貫性を維持する方法についても説明します。', 'Facial Expressions & Emotions in Anime: Drawing Dynamic Character Feelings', 'Capture emotions in anime! Learn to draw expressive faces—joy, anger, sadness—and bring your characters to life with realistic feelings.', 'anime expressions, emotion drawing, facial emotions, character feelings', 'storage/photos/products/2.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Draw the anatomy of anime-style eyes, mouths, and brows to express emotion</li>\r\n  <li>Develop a library of facial expressions for different moods and reactions</li>\r\n  <li>Balance exaggeration and realism to create impactful emotional visuals</li>\r\n  <li>Animate facial expressions for manga panels or storyboard sequences</li>\r\n  <li>Maintain character identity through consistent facial features</li>\r\n</ul>', '<ul>\r\n  <li>アニメ風の目、口、眉の解剖学を描き、感情を表現します</li>\r\n  <li>異なる気分や反応のための表情のライブラリを開発</li>\r\n  <li>誇張とリアリズムのバランスをとって、インパクトのある感情的なビジュアルを作成します</li>\r\n  <li>マンガパネルやストーリーボードのシーケンスの表情をアニメーション化</li>\r\n  <li>一貫した顔の特徴を通じてキャラクターのアイデンティティを維持</li>\r\n</ul>', 1, 0, 0, 4, 'Essentials Series', 'Essentialsシリーズ', 8, 'English & Japanese', '英語＆日本語', NULL, NULL),
(3, 'Designing Iconic Outfits for Anime Worlds', 'アニメの世界のための象徴的な衣装をデザインする', 'designing-iconic-outfits-for-anime-worlds', '', '', 'Costumes and clothing define a character’s personality, background, and the world they inhabit. This course is designed to give you the skills to design iconic, functional, and visually appealing outfits that fit seamlessly into your anime’s narrative.\r\nStarting with fundamentals like fabric behavior, folds, and texture, you’ll learn to create outfits that move naturally and add depth to your characters. You’ll also explore fashion history, cultural influences, and futuristic concepts to build a versatile wardrobe that suits different genres—from fantasy knights to urban school uniforms.\r\nDetailed lessons on color coordination, pattern use, and accessory design will help you enhance your characters’ individuality. With plenty of practical projects and critiques, you’ll build a portfolio of outfit designs ready for animation, manga, or games.', '衣装や服は、キャラクターの個性、背景、そして彼らが生息する世界を定義します。 このコースは、アニメの物語にシームレスにフィットする象徴的で機能的で視覚的に魅力的な衣装をデザインするスキルを提供するように設計されて\r\n生地の振る舞い、折り目、テクスチャなどの基本から始めて、自然に動き、キャラクターに深みを加える衣装を作成する方法を学びます。 また、ファッションの歴史、文化の影響、未来的なコンセプトを探り、ファンタジーの騎士から都市の学校の制服まで、さまざまなジャンルに合った多用途のワードローブを構築します。\r\nカラーコーディネート、パターン使用、アクセサリーデザインに関する詳細なレッスンは、あなたのキャラクターの個性を高めるのに役立ちます。 たくさんの実用的なプロジェクトと批評を使用して、アニメーション、マンガ、またはゲームの準備ができている衣装デザインのポートフォリオを構築します。', 'Designing Iconic Anime Outfits: Costume Creation for Unique Styles', 'Design unforgettable anime outfits! Explore costume theory, fashion trends, and iconic styles to make your characters stand out.', 'anime outfits, costume design, character fashion, iconic styles', 'storage/photos/products/3.webp', 10000, '', '', 'active', 49.00, 7840.00, 392.00, 0.00, 0, '<ul>\r\n  <li>Analyze character roles to design fitting, meaningful costumes</li>\r\n  <li>Illustrate realistic fabric folds and movement in anime style</li>\r\n  <li>Mix cultural and historical references to create original outfits</li>\r\n  <li>Use colors and patterns to enhance character personality</li>\r\n  <li>Add accessories and details that complete and elevate designs</li>\r\n</ul>', '<ul>\r\n  <li>キャラクターの役割を分析し、フィッティング、意味のある衣装を設計する</li>\r\n  <li>アニメスタイルで現実的な生地の折り目と動きを説明</li>\r\n  <li>オリジナルの衣装を作成するために文化的、歴史的な参照をミックス</li>\r\n  <li>文字の個性を高めるために色やパターンを使用してください</li>\r\n  <li>デザインを完成させ、昇格させるアクセサリーや詳細を追加</li>\r\n</ul>', 1, 0, 0, 5, 'Creative Lab', 'クリエイティブラボ', 9, 'English & Japanese', '英語＆日本語', NULL, NULL),
(4, 'From Archetype to Original: Creating Unique Character Concepts', '原型からオリジナルへ：ユニークなキャラクターコンセプトを作成する', 'from-archetype-to-original-creating-unique-character-concepts', '', '', 'Anime thrives on diverse, memorable characters. This course guides you through moving beyond standard archetypes to develop your own unique characters that stand out in crowded genres.\r\nYou’ll start by studying common anime archetypes—the hero, the rival, the mentor—and how they function within stories. Then, through creative exercises, you’ll learn how to subvert, combine, and expand these archetypes into fresh, complex characters with distinct visual and personality traits.\r\nLessons also cover backstory development, motivations, and visual symbolism, enabling you to create characters with depth and relatability. This course equips you with a structured workflow for pitching characters to studios, collaborators, or fans.', 'アニメは多様で記憶に残るキャラクターで繁栄しています。 このコースでは、混雑したジャンルで目立つ独自のユニークなキャラクターを開発するために、標準的なアーキタイプを超えて移動する\r\nヒーロー、ライバル、メンターなどの一般的なアニメの原型と、それらがストーリー内でどのように機能するかを研究することから始めます。 それから、創造的な練習によって、明瞭な視覚および人格特性の新しく、複雑な特性にこれらの原型を破壊し、結合し、拡大する方法を学ぶ。\r\nレッスンはまた裏話の開発、動機および視覚象徴性をカバーし、深さおよびrelatabilityの特性を作成することを可能にする。 このコースでは、スタジオ、コラボレーター、またはファンにキャラクターをピッチングするための構造化されたワークフローを提供します。', 'From Archetype to Original: Crafting Unique Anime Character Concepts', 'Break free from clichés! Develop original anime characters by transforming common archetypes into unique, compelling designs.', 'anime archetypes, original characters, concept design, unique art', 'storage/photos/products/4.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Identify key traits of common anime archetypes and tropes</li>\r\n  <li>Innovate by blending archetypes and adding personal twists</li>\r\n  <li>Develop rich backstories that inform design choices</li>\r\n  <li>Design visual elements that reflect character psychology</li>\r\n  <li>Create professional character concept sheets for pitching</li>\r\n</ul>', '<ul>\r\n  <li>一般的なアニメの原型と比喩の重要な特徴を特定する</li>\r\n  <li>原型をブレンドし、個人的なひねりを加えることによって革新</li>\r\n  <li>デザインの選択を知らせる豊富なバックストーリーを開発</li>\r\n  <li>キャラクター心理を反映したビジュアル要素をデザイン</li>\r\n  <li>ピッチングのためのプロのキャラクターコンセプトシートを作成</li>\r\n</ul>', 1, 0, 0, 4, 'Core Studio', 'コアスタジオ', 7, 'English & Japanese', '英語＆日本語', NULL, NULL),
(5, 'Dynamic Poses & Action Shots for Character Impact', 'キャラクターインパクトのためのダイナミックポーズ＆アクションショット', 'dynamic-poses-and-action-shots-for-character-impact', '', '', 'Static poses can make your characters feel lifeless. This course teaches you how to infuse energy, movement, and drama into your artwork through dynamic posing techniques.\r\nYou’ll explore the anatomy of movement and learn how to use gesture drawing and action lines to capture motion in a single frame. Whether illustrating a tense battle scene or a casual action moment, you’ll learn how to compose poses that communicate power, emotion, and story.\r\nThe course also covers foreshortening, weight distribution, and balance, helping you create believable action shots from multiple angles. By the end, you’ll confidently depict scenes full of energy and flow, vital for anime, manga, and game art.', '静的な姿勢はあなたの特性を活気がない感じさせることができる。 このコースでは、ダイナミックなポージングテクニックを通じて、アートワークにエネルギー、動き、ドラマを注入する方法を教えます。\r\n動きの解剖学的構造を探索し、ジェスチャー描画とアクションラインを使用して単一のフレームで動きをキャプチャする方法を学びます。 緊張した戦闘シーンやカジュアルなアクションの瞬間を示すかどうか、あなたは力、感情、そして物語を伝えるポーズを構成する方法を学びます。\r\nコースはまた、あなたが複数の角度から信じられるアクションショットを作成するのに役立ち、短縮、体重分布、およびバランスをカバーしています。 最終的には、アニメ、マンガ、ゲームアートに欠かせない、エネルギーと流れに満ちたシーンを自信を持って描くことができます。', 'Dynamic Poses & Action Shots: Drawing High-Impact Anime Characters', 'Draw high-energy anime poses! Master action shots, dynamic angles, and movement to make your characters leap off the page.', 'dynamic poses, action drawing, anime movement, impactful art', 'storage/photos/products/5.webp', 10000, '', '', 'active', 49.00, 7840.00, 392.00, 0.00, 0, '<ul>\r\n  <li>Break down complex movements into simplified poses</li>\r\n  <li>Use gesture and line of action to convey dynamic motion</li>\r\n  <li>Apply foreshortening and perspective to action scenes</li>\r\n  <li>Balance anatomical accuracy with artistic exaggeration</li>\r\n  <li>Compose impactful fight sequences and dramatic gestures</li>\r\n</ul>', '<ul>\r\n  <li>複雑な動きを単純化されたポーズに分解</li>\r\n  <li>ジェスチャーとアクションラインを使用して動的な動きを伝えます</li>\r\n  <li>アクションシーンに短縮と視点を適用</li>\r\n  <li>芸術的誇張と解剖学的正確さのバランス</li>\r\n  <li>インパクトのある戦いのシーケンスと劇的なジェスチャーを構成</li>\r\n</ul>', 1, 0, 0, 5, 'Skill Builder', 'スキルビルダー', 8, 'English & Japanese', '英語＆日本語', NULL, NULL),
(6, 'Color Psychology in Character Design', 'キャラクターデザインにおける色彩心理学', 'color-psychology-in-character-design', '', '', 'Color isn’t just decoration—it’s a powerful storytelling tool. This course reveals how to use color psychology to influence how audiences perceive your characters emotionally and symbolically.\r\nYou’ll dive into color theory basics and how to apply them specifically in anime character design. Learn how different hues, saturation levels, and contrasts can evoke feelings like warmth, danger, mystery, or purity. The course explores cultural color meanings and how to create palettes that fit your character’s personality and story arc.\r\nWith practical exercises, you’ll experiment with harmonious and contrasting palettes, learning to design characters that visually communicate their traits at a glance.', '「色は単なる装飾ではなく、強力なストーリーテリングツールです。 このコースでは、色彩心理学を使用して、視聴者があなたのキャラクターを感情的かつ象徴的に知覚する方法に影響を与える方法を明らかにします。\r\n色理論の基本と、アニメのキャラクターデザインに具体的に適用する方法について説明します。 さまざまな色相、彩度レベル、コントラストが、暖かさ、危険、謎、または純粋さなどの感情をどのように呼び起こすかを学びます。 このコースでは、文化的な色の意味と、キャラクターの個性とストーリーアークに合ったパレットを作成する方法を探ります。\r\n実践的な演習では、調和のとれた対照的なパレットを試して、視覚的に一目で彼らの特性を伝える文字を設計することを学びます。\"\"', 'Color Psychology in Anime: How Colors Shape Character Perception', 'Use color like a pro! Understand how hues influence perception and create mood in anime character designs.', 'color theory, anime palette, psychology of color, design mood', 'storage/photos/products/6.webp', 10000, '', '', 'active', 29.00, 4640.00, 232.00, 0.00, 0, '<ul>\r\n  <li>Understand the emotional impact of different colors and combinations</li>\r\n  <li>Develop color palettes that reinforce character traits and moods</li>\r\n  <li>Use color contrasts to create visual focus and depth</li>\r\n  <li>Incorporate cultural symbolism in palette choices</li>\r\n  <li>Apply lighting and shading techniques to enhance color storytelling</li>\r\n</ul>', '<ul>\r\n  <li>異なる色や組み合わせの感情的な影響を理解する</li>\r\n  <li>キャラクターの特徴や気分を強化するカラーパレットを開発</li>\r\n  <li>色のコントラストを使用して視覚的な焦点と深さを作成します</li>\r\n  <li>パレットの選択に文化的象徴を組み込む</li>\r\n  <li>色のストーリーテリングを強化するために照明とシェーディング技術を適用</li>\r\n</ul>', 1, 0, 0, 3, 'Creative Lab', 'クリエイティブラボ', 6, 'English & Japanese', '英語＆日本語', NULL, NULL),
(12, 'Perspective Drawing for Anime Backgrounds', 'アニメの背景のための遠近法の描画', 'perspective-drawing-for-anime-backgrounds', '', '', 'Creating believable, immersive anime backgrounds begins with mastering perspective, the foundation of spatial realism and depth in your scenes. This course is designed to take you from the basics to advanced perspective techniques specifically tailored for anime-style environments.\r\nYou will learn how to construct 1-, 2-, and 3-point perspective grids and apply them to a variety of scenes including bustling cityscapes, detailed interiors, and vast landscapes. The course emphasizes practical application with step-by-step demonstrations, helping you integrate characters seamlessly into these environments.\r\nThrough numerous exercises, you’ll develop the confidence to accurately depict buildings, roads, furniture, and natural elements with depth and proportion, enhancing the believability of your worlds. Whether you are illustrating manga, storyboards, or animation backgrounds, this course equips you to create stunning, professional-quality settings.', '信じられない、没入型のアニメの背景を作成することは、視点、あなたのシーンの空間的なリアリズムと深さの基礎を習得することから始ま このコースは、アニメスタイルの環境に特化した基本から高度な視点技術まで、あなたを取るように設計されています。\r\n1点、2点、3点のパースペクティブグリッドを構築し、賑やかな街並み、詳細なインテリア、広大な風景など、さまざまなシーンに適用する方法を学びます。 このコースでは、ステップバイステップのデモで実用的なアプリケーションを強調し、文字をこれらの環境にシームレスに統合するのに役立ちます。\r\n多数の練習によって、正確にあなたの世界の信憑性を高める深さおよび割合の建物、道、家具および自然な要素を描写するために信任を開発する。 マンガ、ストーリーボード、またはアニメーションの背景を説明しているかどうか、このコースは、見事な、プロ品質の設定を作成するためにあなたを装備します。', 'Perspective Drawing for Anime Backgrounds: Depth & Composition', 'Master perspective for anime backgrounds! Learn 1-point, 2-point, and 3-point techniques for immersive scenes.', 'perspective drawing, anime backgrounds, depth, composition', 'storage/photos/products/12.webp', 10000, '', '', 'active', 59.00, 9440.00, 472.00, 0.00, 0, '<ul>\r\n  <li>Set up and utilize perspective grids for complex scenes</li>\r\n  <li>Draw architectural structures and interior spaces with accuracy</li>\r\n  <li>Use vanishing points creatively to enhance composition</li>\r\n  <li>Integrate characters naturally within backgrounds</li>\r\n  <li>Avoid common perspective errors that break immersion</li>\r\n</ul>\r\n', '<ul>\r\n  <li>複雑なシーンにパースペクティブグリッドを設定して活用</li>\r\n  <li>建築構造や内部空間を正確に描く</li>\r\n  <li>組成を強化するために創造的に消失点を使用</li>\r\n  <li>背景内に自然に文字を統合</li>\r\n  <li>浸漬を破る一般的な遠近法のエラーを避ける</li>\r\n</ul>', 2, 0, 0, 5, 'Foundations Series', '基礎シリーズ', 9, 'English & Japanese', '英語＆日本語', NULL, NULL),
(13, 'Designing Fantasy and Futuristic Worlds in Anime', 'アニメでファンタジーと未来的な世界をデザインする', 'designing-fantasy-and-futuristic-worlds-in-anime', '', '', 'Transport your audience to awe-inspiring realms by mastering the art of designing fantasy and futuristic anime worlds. This course guides you through the process of conceptualizing and illustrating environments that evoke wonder and fit seamlessly within anime storytelling.\r\nYou’ll explore techniques for combining realism with imagination—balancing practical architectural rules with creative liberties to build cities in the clouds, dystopian urban sprawls, enchanted forests, and otherworldly landscapes. Learn how to develop consistent visual language for technology, flora, fauna, and cultural elements unique to your world.\r\nThe course also covers how to use lighting, color, and atmospheric effects to amplify mood and narrative impact, enabling you to create environments that feel alive and integral to your story.', 'ファンタジーと未来的なアニメの世界を設計する芸術を習得することによって、畏敬の念を起こさせるレルムにあなたの聴衆を輸送します。 このコースでは、不思議を呼び起こし、アニメのストーリーテリングにシームレスに適合する環境を概念化し、説明するプロセスをガイドします。\r\n現実主義と想像力を組み合わせるためのテクニックを探ります—実用的な建築ルールと創造的な自由のバランスをとり、雲の中の都市、ディストピアの都市の広がり、魅惑的な森、そして別世界の風景を構築します。 あなたの世界に固有の技術、動植物、文化的要素のための一貫した視覚言語を開発する方法を学びます。\r\nこのコースでは、照明、色、大気の効果を使用して気分や物語の影響を増幅する方法についても説明し、ストーリーに生き生きと不可欠であると感じる環境を作', 'Designing Fantasy & Futuristic Worlds for Anime & Manga', 'Build fantasy/sci-fi anime worlds! Design castles, futuristic cities, and otherworldly landscapes.', 'fantasy worlds, sci-fi anime, worldbuilding, environment design', 'storage/photos/products/13.webp', 10000, '', '', 'active', 49.00, 7840.00, 392.00, 0.00, 0, '<ul>\r\n  <li>Conceptualize detailed fantasy and sci-fi settings from rough sketches to final art</li>\r\n  <li>Design unique architectural and natural elements fitting your world&rsquo;s theme</li>\r\n  <li>Balance stylization and realism to achieve immersive visuals</li>\r\n  <li>Apply atmospheric perspective and lighting to convey mood and scale</li>\r\n  <li>Build a cohesive world with consistent visual storytelling elements</li>\r\n</ul>', '<ul>\r\n  <li>ラフスケッチから最終的なアートまで、詳細なファンタジーとsfの設定を概念化</li>\r\n  <li>あなたの世界＆rsquoに合ったユニークな建築と自然の要素を設計し、sのテーマ</li>\r\n  <li>没入型ビジュアルを実現するためのスタイル化とリアリズムのバランス</li>\r\n  <li>気分やスケールを伝えるために大気の視点と照明を適用</li>\r\n  <li>一貫性のある視覚的なストーリーテリング要素で凝集の世界を構築</li>\r\n</ul>', 2, 0, 0, 5, 'Core Studio', 'コアスタジオ', 8, 'English & Japanese', '英語＆日本語', NULL, NULL),
(14, 'Creating Cozy Interiors and Iconic Exteriors', '居心地の良いインテリアと象徴的な外観を作成する', 'creating-cozy-interiors-and-iconic-exteriors', '', '', 'Designing interiors and exteriors that resonate with viewers is key to making your anime settings memorable and emotionally engaging. This course helps you master creating warm, lived-in spaces as well as bold, iconic exteriors that serve as visual anchors in your narrative.\r\nLearn how to compose interiors that reflect the personalities and lifestyles of your characters through furniture choices, decor, and spatial arrangement. Explore lighting techniques that turn ordinary rooms into evocative storytelling scenes—from sunlit kitchens to moody bedrooms.\r\nFor exterior scenes, the course covers how to design buildings, streets, and landmarks with strong silhouettes and memorable details, all while maintaining clear readability and anime styling.', '「視聴者と共鳴するインテリアや外装をデザインすることは、アニメの設定を思い出深いものにし、感情的に魅力的にするための鍵です。 このコースでは、あなたの物語の視覚的なアンカーとして機能する大胆な、象徴的な外観だけでなく、暖かく、住んでいたスペースの作成を習得するのに役立\r\n家具の選択、装飾、空間的な配置を通して、キャラクターの個性やライフスタイルを反映したインテリアを構成する方法を学びます。 太陽に照らされた台所からの不機嫌な寝室への刺激的な物語の場面に普通の部屋を回す照明技術を探検しなさい。\r\n外装シーンでは、明確な読みやすさとアニメのスタイリングを維持しながら、強いシルエットと思い出に残るディテールで建物、通り、ランドマークをデザインする方法をカバーしています。\"\"', 'Creating Cozy Interiors & Iconic Exteriors for Anime Scenes', 'Create cozy rooms and epic exteriors! Learn composition, lighting, and detail for anime settings.', 'anime interiors, exterior art, cozy scenes, iconic locations', 'storage/photos/products/14.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Compose interiors that communicate character and story without words</li>\r\n  <li>Use lighting and shadows to create atmosphere and depth in rooms</li>\r\n  <li>Design striking exteriors that complement your story’s setting</li>\r\n  <li>Add authentic props and details to enrich environments</li>\r\n  <li>Balance realism and stylization for visual appeal and clarity</li>\r\n</ul>\r\n', '<ul>\r\n  <li>言葉を使わずにキャラクターやストーリーを伝えるインテリアを構成</li>\r\n  <li>部屋の雰囲気と深さを作成するために照明と影を使用してください</li>\r\n  <li>あなたの物語の設定を補完する印象的な外観をデザイン</li>\r\n  <li>環境を豊かにするために本物の小道具と詳細を追加</li>\r\n  <li>視覚的な魅力と明快さのためのリアリズムと様式化のバランス</li>\r\n</ul>', 2, 0, 0, 4, 'Essentials Series', 'Essentialsシリーズ', 7, 'English & Japanese', '英語＆日本語', NULL, NULL),
(15, 'Storytelling Through Environment: Visual Clues & Symbols', '環境を通じたストーリーテリング：視覚的な手がかりとシンボル', 'storytelling-through-environment-visual-clues-and-symbols', '', '', 'Your anime world is a silent narrator — this course teaches you how to embed powerful storytelling through environment design. Learn how to use visual clues and symbols in backgrounds and settings to deepen your narrative and add layers of meaning.\r\nYou will discover how details like weathered walls, scattered objects, and background graffiti can hint at plot points, character histories, and emotional undertones. The course emphasizes subtlety and coherence, teaching you to design environments that reward close viewers and enrich the story without distracting from the main action.\r\nWhether you’re creating manga panels or animated backgrounds, this course will elevate your work by turning your environments into integral storytelling elements.', 'このコースでは、環境デザインを通じて強力なストーリーテリングを埋め込む方法を教えています。 あなたの物語を深め、意味の層を追加するために、背景や設定で視覚的な手がかりやシンボルを使用する方法を学びます。\r\n風化した壁、散在したオブジェクト、背景の落書きなどの詳細が、プロットポイント、キャラクターの歴史、感情的な色調をどのように示唆しているかを発見できます。 このコースでは、繊細さと一貫性を強調し、主な行動から気を散らすことなく、近くの視聴者に報酬を与え、物語を豊かにする環境を設計することを教え\r\nマンガパネルやアニメーションの背景を作成しているかどうかにかかわらず、このコースでは、環境を不可欠なストーリーテリング要素に変えることで、作業を向上させることができます。\"\"', 'Storytelling Through Anime Environments: Visual Clues & Symbols', 'Tell stories through environments! Use visual clues, props, and symbolism in anime backgrounds.', 'environment storytelling, visual clues, symbolic art, scene details', 'storage/photos/products/15.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Identify opportunities to add symbolic details to your scenes</li>\r\n  <li>Design backgrounds that reflect character and story development</li>\r\n  <li>Use environmental storytelling to foreshadow and build tension</li>\r\n  <li>Balance subtlety and clarity for effective visual narrative</li>\r\n  <li>Incorporate cultural and thematic symbolism into designs</li>\r\n</ul>\r\n', '<ul>\r\n  <li>シーンに象徴的な詳細を追加する機会を特定する</li>\r\n  <li>キャラクターやストーリーの展開を反映したデザインの背景</li>\r\n  <li>環境ストーリーテリングを使用して前兆と緊張を構築</li>\r\n  <li>効果的な視覚的な物語のための微妙さと明快さのバランス</li>\r\n  <li>デザインに文化的、テーマ的な象徴を組み込む</li>\r\n</ul>', 2, 0, 0, 4, 'Narrative Design Series', 'ナラティブデザインシリーズ', 8, 'English & Japanese', '英語＆日本語', NULL, NULL),
(16, 'Lighting and Color Grading for Scene Mood', '場面気分のために等級別になる照明および色', 'lighting-and-color-grading-for-scene-mood', '', '', 'The emotional tone of an anime scene often hinges on lighting and color choices. This course dives deep into how to manipulate light and color to craft moods, highlight drama, and guide viewer focus within your anime environments.\r\nYou’ll study different lighting setups—such as dawn, dusk, night, and interior artificial lighting—and how they affect color temperature, shadows, and reflections. Learn how to use color grading to unify scenes, evoke specific feelings, and create cinematic effects.\r\nPractical assignments will help you experiment with lighting direction, intensity, and color overlays, giving you tools to make your scenes more vibrant, moody, or ethereal according to your story needs.', '「アニメシーンの感情的なトーンは、照明と色の選択に左右されることがよくあります。 このコースでは、光と色を操作して気分を作り、ドラマを強調し、アニメ環境内で視聴者の焦点を導く方法について深く掘り下げます。\r\n夜明け、夕暮れ、夜、室内の人工照明など、さまざまな照明設定と、それらが色温度、影、反射にどのように影響するかを調べます。 カラーグレーディングを使用して、シーンを統一し、特定の感情を呼び起こし、映画のような効果を作成する方法を学びます。\r\n実用的な課題は、照明の方向、強度、およびカラーオーバーレイを試すのに役立ち、ストーリーのニーズに応じてシーンをより活気に満ちた、不機嫌な、または空気のようなものにするためのツールを提供します。\"\"', 'Lighting & Color Grading for Mood in Anime Backgrounds', 'Set the mood with lighting! Master color grading, shadows, and ambiance for anime scenes.', 'lighting techniques, color grading, mood setting, anime scenes', 'storage/photos/products/16.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Apply lighting techniques that enhance atmosphere and realism</li>\r\n  <li>Use color grading to unify scene elements and reinforce tone</li>\r\n  <li>Create dramatic contrasts and subtle gradations with light and shadow</li>\r\n  <li>Simulate different times of day and weather effects with color</li>\r\n  <li>Enhance storytelling with targeted lighting cues and effects</li>\r\n</ul>\r\n', '<ul>\r\n  <li>雰囲気とリアリズムを高める照明技術を適用</li>\r\n  <li>カラーグレーディングを使用してシーン要素を統一し、トーンを強化</li>\r\n  <li>光と影で劇的なコントラストと微妙なグラデーションを作成</li>\r\n  <li>色で一日と天候の効果の異なる時間をシミュレート</li>\r\n  <li>ターゲットを絞った照明の手がかりと効果でストーリーテリングを強化</li>\r\n</ul>', 2, 0, 0, 4, 'Creative Lab', 'クリエイティブラボ', 7, 'English & Japanese', '英語＆日本語', NULL, NULL),
(23, 'How to Create Manga Panels That Flow', '流れてくるマンガパネルの作り方', 'how-to-create-manga-panels-that-flow', '', '', 'Learn the art of turning ideas into compelling visual narratives with this in-depth course on manga paneling and storytelling. Manga isn’t just about drawing—it’s about guiding your reader through a carefully choreographed sequence of moments that build emotion, tension, and pace.\r\nThis course teaches you how to structure pages, arrange panels, and frame scenes to control the rhythm of your story. You’ll study master manga artists’ work to understand panel size, flow, and transitions. Then, you’ll apply those lessons to your own scripts and scenes.\r\nWhether you’re working on slice-of-life or shonen action, you’ll discover how paneling can elevate your storytelling, making your manga more dynamic, readable, and impactful.', '「マンガパネルとストーリーテリングに関するこの詳細なコースで、アイデアを魅力的な視覚的な物語に変える芸術を学びましょう。 マンガは絵を描くことだけではなく、感情、緊張、ペースを構築する慎重に振り付けられた瞬間のシーケンスを通して読者を導くことです。\r\nこのコースでは、ページの構造、パネルの配置、シーンのフレームを作成して、ストーリーのリズムを制御する方法を説明します。 マンガ家の仕事を勉強して、パネルのサイズ、流れ、トランジションを理解します。 次に、これらのレッスンを独自のスクリプトやシーンに適用します。\r\nあなたはスライス*オブ*ライフや少年アクションに取り組んでいるかどうか、あなたは羽目板は、あなたの漫画をよりダイナミックで読みやすく、インパクト\"\"', 'How to Create Flowing Manga Panels: Layout & Pacing', 'Craft seamless manga flow! Panel layouts, pacing, and reader engagement techniques.', 'manga panels, flow, pacing, reader engagement, layout', 'storage/photos/products/23.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Plan and layout manga pages using dynamic paneling techniques</li>\r\n  <li>Control narrative pacing with panel size and composition</li>\r\n  <li>Convey mood, tone, and emotion through framing and flow</li>\r\n  <li>Seamlessly guide the reader’s eye across each page</li>\r\n  <li>Use splash pages and visual rhythm to create dramatic impact</li>\r\n</ul>\r\n', '<ul>\r\n  <li>動的羽目板技術を使用したマンガページの計画とレイアウト</li>\r\n  <li>パネルのサイズと構成で物語のペーシングを制御</li>\r\n  <li>フレーミングとフローを通じて気分、トーン、感情を伝える</li>\r\n  <li>シームレスに各ページ全体で読者の目を導きます</li>\r\n  <li>スプラッシュページと視覚的なリズムを使用して劇的な影響を作成します</li>\r\n</ul>', 3, 0, 0, 4, 'Core Studio', 'コアスタジオ', 8, 'English & Japanese', '英語＆日本語', NULL, NULL),
(24, 'Black-and-White Manga Inking Techniques', '白黒マンガの墨入れのテクニック', 'black-and-white-manga-inking-techniques', '', '', 'Bring your linework to life with inking techniques that define manga’s timeless style. In this course, you’ll master the tools and strategies used by professional manga artists to create bold, expressive black-and-white art.\r\nFrom using pressure-sensitive strokes to creating contrast with line weight, you’ll explore how to make characters pop and scenes feel textured and full of motion. Whether you prefer digital or traditional methods, you’ll finish this course with the confidence to ink clean, publish-ready manga pages.', 'マンガの時代を超越したスタイルを定義するインク技術であなたのラインワークを生き生きとさせてください。 このコースでは、プロの漫画家が大胆で表現力豊かな白黒アートを作成するために使用するツールと戦略を習得します。\r\n感圧ストロークの使用から、線の太さとのコントラストの作成まで、キャラクターをポップにしたり、シーンをテクスチャや動きに満ちた感じにする方法を探ります。 あなたはデジタルまたは伝統的な方法を好むかどうか、あなたはきれいなインクに自信を持ってこのコースを終了します,出版準備マンガページ.', 'Black & White Manga Inking: Professional Line Art Techniques', 'Professional inking for manga! Line weight, texture, and black-and-white contrast tips.', 'inking techniques, line art, manga style, black and white', 'storage/photos/products/24.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Control line weight and texture to create depth and focus</li>\r\n  <li>Use solid blacks, hatching, and outlines to define form</li>\r\n  <li>Maintain character consistency and style across pages</li>\r\n  <li>Apply both digital and traditional inking techniques</li>\r\n  <li>Clean up and refine your work for professional-quality results</li>\r\n</ul>\r\n', '<ul>\r\n  <li>深さと焦点を作成するための制御線の太さとテクスチャ</li>\r\n  <li>固体の黒、ハッチング、および輪郭を使用してフォームを定義します</li>\r\n  <li>ページ間で文字の一貫性とスタイルを維持</li>\r\n  <li>デジタルと伝統的なインク技術の両方を適用</li>\r\n  <li>クリーンアップし、プロ品質の結果のためにあなたの仕事を洗練</li>\r\n</ul>', 3, 0, 0, 4, 'Essentials Series', 'Essentialsシリーズ', 7, 'English & Japanese', '英語＆日本語', NULL, NULL),
(25, 'Screen Tones, Patterns & Shading in Manga', '漫画のスクリーントーン、パターン＆シェーディング', 'screen-tones-patterns-and-shading-in-manga', '', '', 'Screen tones aren’t just decoration — they’re the soul of manga shading. This course teaches you how to use halftones, patterns, and grayscale to add mood, depth, and visual storytelling to your pages.\r\nYou’ll experiment with light and shadow, atmospheric effects, and character highlights. Learn how to use screen tones to indicate material, emotion, or energy in a scene without muddying your composition. You\'ll also discover time-saving techniques and tools that help your work look polished and intentional.', '「画面のトーンは単なる装飾ではなく、マンガの陰影の魂です。 このコースでは、ハーフトーン、パターン、グレースケールを使用して、ページにムード、深み、視覚的なストーリーテリングを追加する方法を説明します。\r\n光と影、大気の効果、キャラクターのハイライトを試してみましょう。 画面のトーンを使用して、構図を混乱させることなく、シーン内の素材、感情、またはエネルギーを示す方法を学びます。 また、作業が洗練され意図的に見えるようにするための時間節約のテクニックやツールも発見できます。\"\"', 'Screen Tones & Shading in Manga: Texture & Depth Tips', 'Master screen tones & shading! Add depth and texture to manga art.', 'screen tones, shading, patterns, texture, manga effects', 'storage/photos/products/25.webp', 10000, '', '', 'active', 29.00, 4640.00, 232.00, 0.00, 0, '<ul>\r\n  <li>Apply tones to backgrounds, clothing, and characters effectively</li>\r\n  <li>Create soft shading, gradients, and textures using patterns</li>\r\n  <li>Combine tone layers for complexity and storytelling impact</li>\r\n  <li>Use screen tones to enhance lighting, drama, and mood</li>\r\n  <li>Master digital tools for screen tone application and editing</li>\r\n</ul>\r\n', '<ul>\r\n  <li>背景、衣服、文字に効果的にトーンを適用</li>\r\n  <li>パターンを使用してソフトシェーディング、グラデーション、テクスチャを作成</li>\r\n  <li>複雑さとストーリーテリングの影響のためのトーン層を組み合わせる</li>\r\n  <li>照明、ドラマ、気分を高めるために画面のトーンを使用してください</li>\r\n  <li>画面トーンアプリケーションと編集のためのマスターデジタルツール</li>\r\n</ul>', 3, 0, 0, 3, 'Creative Lab', 'クリエイティブラボ', 6, 'English & Japanese', '英語＆日本語', NULL, NULL),
(26, 'Action Panels: Speed Lines, Impact Frames, and FX', 'アクションパネル：スピードライン、インパクトフレーム、およびFX', 'action-panels-speed-lines-impact-frames-and-fx', '', '', 'Explosive punches. Lightning-fast dodges. Earth-shaking clashes. This course breaks down the essential visual language behind powerful manga action. You\'ll learn how to amplify movement and emotion through speed lines, dynamic angles, and stylized FX that leap off the page.\r\nUsing real examples and hands-on challenges, you’ll create energy-filled scenes that match the intensity of top shonen manga. From melee duels to magic battles, this course teaches you how to bring motion into still images.', '「爆発的なパンチ。 電光石火のように速くかわします。 地球を揺るがす衝突。 このコースでは、強力なマンガアクションの背後にある本質的な視覚言語を分解します。 スピードライン、ダイナミックな角度、ページから飛び降りる様式化されたFXを通じて、動きと感情を増幅する方法を学びます。\r\n実際の例と実践的な課題を使用して、あなたはトップ少年漫画の強度に一致するエネルギーに満ちたシーンを作成します。 このコースでは、近接戦闘から魔法の戦いまで、静止画に動きをもたらす方法を教えています。\"\"', 'Action Manga Panels: Speed Lines, Impact Frames & FX', 'Dynamic action manga panels! Speed lines, impact frames, and special FX.', 'action manga, speed lines, impact frames, special FX', 'storage/photos/products/26.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Use speed lines to show velocity and energy</li>\r\n  <li>Frame action using angled panels and strategic foreshortening</li>\r\n  <li>Draw impact effects, visual sound FX, and debris for realism</li>\r\n  <li>Sequence motion for clarity and emotional pacing</li>\r\n  <li>Combine character poses with background effects for maximum impact</li>\r\n</ul>\r\n', '<ul>\r\n  <li>速度線を使用して速度とエネルギーを表示</li>\r\n  <li>角度付きパネルを使用したフレームアクションと戦略的な短縮</li>\r\n  <li>インパクトエフェクト、ビジュアルサウンドFX、リアリズムのための破片を描く</li>\r\n  <li>明快さと感情的なペーシングのためのシーケンスモーション</li>\r\n  <li>最大のインパクトのための背景効果と文字のポーズを組み合わせる</li>\r\n</ul>', 3, 0, 0, 4, 'Skill Builder', 'スキルビルダー', 8, 'English & Japanese', '英語＆日本語', NULL, NULL),
(27, 'Expressive Dialogue Bubbles and Lettering', '表現力豊かな対話の泡とレタリング', 'expressive-dialogue-bubbles-and-lettering', '', '', 'Manga dialogue isn\'t just what characters say — it\'s how they say it. This course covers the art of expressive speech bubbles, fonts, and lettering that reflect tone, personality, and emotion.\r\nYou’ll explore how bubble shape, placement, and style influence pacing and rhythm, and learn how to match your typography to the scene\'s emotional intensity. Whether you’re hand lettering or using digital tools, you’ll walk away knowing how to make your dialogue feel as dynamic as your artwork.', '「マンガの対話は、キャラクターが言うことだけではなく、彼らが言う方法です。 このコースでは、表現力豊かな吹き出し、フォント、レタリング、人格、感情を反映する芸術をカバーしています。\r\nバブルの形、配置、スタイルがペーシングとリズムにどのように影響するかを調べ、タイポグラフィをシーンの感情的な強さに合わせる方法を学びます。 あなたが手のレタリングやデジタルツールを使用しているかどうか、あなたはあなたの対話があなたのアートワークのようにダイナミックに感じさせる方法を知って離れて歩くでしょう。\"\"', 'Expressive Manga Dialogue Bubbles & Lettering Techniques', 'Design expressive speech bubbles! Lettering styles and dialogue flow for manga.', 'dialogue bubbles, lettering, manga text, speech art', 'storage/photos/products/27.webp', 10000, '', '', 'active', 29.00, 4640.00, 232.00, 0.00, 0, '<ul>\r\n  <li>Design speech bubbles that match tone (whispers, yells, sarcasm)</li>\r\n  <li>Place bubbles to maintain flow and avoid clutter</li>\r\n  <li>Use hand lettering and digital fonts for impact and clarity</li>\r\n  <li>Create sound effects (SFX) that visually enhance storytelling</li>\r\n  <li>Avoid common lettering mistakes that disrupt reader immersion</li>\r\n</ul>\r\n', '<ul>\r\n  <li>トーンに合ったデザインのスピーチバブル（ささやき、叫び、皮肉）</li>\r\n  <li>流れを維持し、混乱を避けるために泡を置きます</li>\r\n  <li>インパクトと明快さのために手のレタリングとデジタルフォントを使用</li>\r\n  <li>視覚的にストーリーテリングを強化する効果音（SFX）を作成</li>\r\n  <li>読者の浸漬を混乱させる一般的なレタリングの間違いを避ける</li>\r\n</ul>', 3, 0, 0, 3, 'Narrative Design Series', 'ナラティブデザインシリーズ', 6, 'English & Japanese', '英語＆日本語', NULL, NULL),
(28, 'Creating a Short Manga: From Script to Page', '短いマンガを作成する：スクリプトからページへ', 'creating-a-short-manga-from-script-to-page', '', '', 'Turn your idea into a finished manga in this start-to-finish course designed to guide you through the full process. From developing a script to thumbnailing, paneling, inking, and adding tones — this course walks you through every stage with a focus on short-format manga (8–16 pages).\r\nPerfect for first-time creators or zine-style projects, this course teaches both the creative and technical sides of storytelling, including how to prepare your manga for print or web publication.', '\"\"完全なプロセスをガイドするように設計されたこの最初から最後までのコースで、あなたのアイデアを完成したマンガに変えてください。 このコースでは、スクリプトの開発からサムネイル、パネル、インク、トーンの追加まで、短い形式のマンガ（8—16ページ）に焦点を当てて、すべてのステージを順\r\n初めてのクリエイターやzineスタイルのプロジェクトに最適なこのコースでは、印刷物やweb出版のために漫画を準備する方法など、ストーリーテリングの創造的\"\"', 'Creating a Short Manga: Script to Finished Page Guide', 'Make your own short manga! From scripting to finished pages—step-by-step guide.', 'short manga, scripting, page layout, comic creation', 'storage/photos/products/28.webp', 10000, '', '', 'active', 59.00, 9440.00, 472.00, 0.00, 0, '<ul>\r\n  <li>Write a complete short-form story that fits a small page count</li>\r\n  <li>Break down scripts into scenes, then pages, then panels</li>\r\n  <li>Manage your drawing workflow from sketch to final</li>\r\n  <li>Apply tones, SFX, and dialogue bubbles professionally</li>\r\n  <li>Export your manga for digital release or print production</li>\r\n</ul>\r\n', '<ul>\r\n  <li>小さなページ数に合った完全なショートフォームのストーリーを書く</li>\r\n  <li>スクリプトをシーン、ページ、パネルに分割します</li>\r\n  <li>sketchからfinalまでの描画ワークフローを管理します</li>\r\n  <li>トーン、SFX、および対話の泡を専門的に適用</li>\r\n  <li>デジタルリリースや印刷生産のためにあなたの漫画をエクスポート</li>\r\n</ul>', 3, 0, 0, 5, 'Project Lab', 'プロジェクトラボ', 10, 'English & Japanese', '英語＆日本語', NULL, NULL),
(34, 'Anime Coloring Techniques: Cel vs Soft Shading', 'アニメの着色技術：セル対ソフトシェーディング', 'anime-coloring-techniques-cel-vs-soft-shading', '', '', 'Step into the world of anime coloring by mastering two of its most iconic styles: crisp cel shading and smooth soft shading. This course breaks down the strengths, use-cases, and workflows of each technique so you can choose and execute the perfect coloring style for your project.\r\nYou’ll learn industry-standard approaches used in anime production and illustration—how to separate flats, apply shading layers, and bring out volume, lighting, and tone using digital tools. Whether you want the classic anime look or a more painterly feel, this course is your gateway to stunning color work.', '「鮮明なセルシェーディングと滑らかなソフトシェーディングの2つの最も象徴的なスタイルをマスターして、アニメのカラーリングの世界に足を踏み入れ このコースでは、各テクニックの強み、ユースケース、ワークフローを分解して、プロジェクトに最適なカラーリングスタイルを選択して実行できます。\r\nデジタルツールを使用して、フラットを分離し、シェーディングレイヤーを適用し、ボリューム、照明、トーンを引き出す方法など、アニメ制作やイラストで使用される業界標準のアプローチを学びます。 あなたは古典的なアニメの外観やより絵画的な感触をしたいかどうか、このコースは見事な色の仕事へのあなたのゲートウェイです。\"\"', 'Anime Coloring Techniques: Cel vs. Soft Shading Guide', 'Cel vs. soft shading in anime! Techniques for vibrant or painterly styles.', 'anime coloring, cel shading, soft shading, digital art', 'storage/photos/products/34.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Understand the visual logic behind cel vs soft shading</li>\r\n  <li>Apply light, shadow, and highlights with precision</li>\r\n  <li>Create sharp edges, soft transitions, and mixed styles</li>\r\n  <li>Use layer modes (Multiply, Overlay, etc.) effectively</li>\r\n  <li>Color characters and backgrounds with harmony and contrast</li>\r\n</ul>\r\n', '<ul>\r\n  <li>セルとソフトシェーディングの背後にある視覚的なロジックを理解する</li>\r\n  <li>光、影、ハイライトを正確に適用</li>\r\n  <li>シャープなエッジ、ソフトトランジション、および混合スタイルを作成</li>\r\n  <li>レイヤーモード（乗算、オーバーレイなど）を使用します。）効果的に</li>\r\n  <li>調和とコントラストを持つ色の文字と背景</li>\r\n</ul>\r\n', 4, 0, 0, 4, 'Essentials Series', 'Essentialsシリーズ', 7, 'English & Japanese', '英語＆日本語', NULL, NULL),
(35, 'Mastering Light and Shadow in Digital Art', 'デジタルアートで光と影をマスターする', 'mastering-light-and-shadow-in-digital-art', '', '', 'Lighting transforms a good illustration into a cinematic one. This course helps you master the principles of digital lighting and shadow, teaching you how to use contrast, color temperature, and ambient light to add drama, mood, and realism to anime-style artwork.\r\nYou\'ll study different lighting scenarios—indoor, outdoor, magical, and night scenes—and learn how to cast believable shadows that add depth and dimension. Ideal for those looking to level up their artwork with atmospheric storytelling and eye-catching visuals.', '\"\"照明は良いイラストを映画のようなものに変えます。 このコースでは、デジタル照明と影の原則を習得し、コントラスト、色温度、周囲の光を使用して、アニメスタイルのアートワークにドラマ、ムード、リアリズムを追\r\n屋内、屋外、魔法、夜のシーンなど、さまざまな照明シナリオを研究し、深さと次元を追加する信じられないほどの影をキャストする方法を学びます。 雰囲気のあるストーリーテリングと目を引くビジュアルでアートワークをレベルアップしたい方に最適です。\"\"', 'Mastering Light & Shadow in Digital Anime Art', 'Light & shadow mastery! Create depth and realism in digital anime art.', 'light and shadow, depth, realism, digital painting', 'storage/photos/products/35.webp', 10000, '', '', 'active', 49.00, 7840.00, 392.00, 0.00, 0, '<ul>\r\n  <li>Apply light direction and shadow casting accurately</li>\r\n  <li>Use color theory to create emotional lighting effects</li>\r\n  <li>Simulate natural vs artificial light sources</li>\r\n  <li>Create mood through rim light, bounce light, and contrast</li>\r\n  <li>Paint reflective surfaces and glowing elements</li>\r\n</ul>', '<ul>\r\n  <li>光の方向と影のキャストを正確に適用</li>\r\n  <li>感情的な照明効果を作成するために色理論を使用してください</li>\r\n  <li>自然と人工の光源をシミュレート</li>\r\n  <li>リムライト、バウンスライト、コントラストを通じてムードを作成</li>\r\n  <li>反射面と輝く要素をペイント</li>\r\n</ul>', 4, 0, 0, 4, 'Core Studio', 'コアスタジオ', 8, 'English & Japanese', '英語＆日本語', NULL, NULL),
(36, 'Creating Striking Anime Key Visuals', '印象的なアニメキービジュアルを作成する', 'creating-striking-anime-key-visuals', '', '', 'Key visuals are the high-impact illustrations that define anime marketing. In this course, you’ll learn how to create powerful standalone artworks that represent a character, scene, or story — often used in posters, covers, and promotional material.\r\nFrom choosing dramatic poses and camera angles to composing a balanced layout, this course teaches you how to design illustrations that communicate both emotion and narrative at a glance.', 'キービジュアルは、アニメマーケティングを定義するインパクトの高いイラストです。 このコースでは、キャラクター、シーン、またはストーリーを表す強力なスタンドアロンアートワークを作成する方法を学びます。\r\nドラマチックなポーズやカメラアングルの選択から、バランスの取れたレイアウトの構成まで、感情と物語の両方を一目で伝えるイラストをデザインする方法を学びます。', 'Creating Striking Anime Key Visuals: Poster-Worthy Art', 'Design poster-worthy key visuals! Composition, impact, and storytelling.', 'key visuals, poster art, impactful scenes, anime promo', 'storage/photos/products/36.webp', 10000, '', '', 'active', 59.00, 9440.00, 472.00, 0.00, 0, '<ul>\r\n  <li>Conceptualize high-impact visual themes</li>\r\n  <li>Compose dramatic, cinematic poses and angles</li>\r\n  <li>Balance focus between character and background</li>\r\n  <li>Use lighting, effects, and typography to enhance storytelling</li>\r\n  <li>Prepare your visual for print, banners, and online platforms</li>\r\n</ul>', '<ul>\r\n  <li>インパクトの高いビジュアルテーマを概念化</li>\r\n  <li>劇的な、映画のポーズと角度を構成</li>\r\n  <li>文字と背景の間のバランスの焦点</li>\r\n  <li>ライティング、エフェクト、タイポグラフィを使用してストーリーテリングを強化</li>\r\n  <li>印刷、バナー、オンラインプラットフォーム用のビジュアルを準備します</li>\r\n</ul>', 4, 0, 0, 5, 'Skill Builder', 'スキルビルダー', 9, 'English & Japanese', '英語＆日本語', NULL, NULL),
(37, 'Illustrating Group Shots and Character Interactions', 'グループショットとキャラクターの相互作用の説明', 'illustrating-group-shots-and-character-interactions', '', '', 'Creating natural, dynamic interactions between multiple characters is a hallmark of strong anime illustration. This course teaches you how to pose, place, and connect multiple characters in a shared scene—whether it\'s a slice-of-life group shot or a tense ensemble moment.\r\nYou’ll learn how to balance size, focus, and perspective across the scene, while keeping each character visually unique and expressive. It’s the perfect course for anyone working on covers, cast lineups, or promotional art for anime-inspired stories.', '複数のキャラクター間の自然で動的な相互作用を作成することは、強力なアニメイラストの特徴です。 このコースでは、共有シーンで複数のキャラクターをポーズ、配置、接続する方法を教えています—それはスライスの人生のグループショットや緊張したアンサンブルの瞬間であるかどうか。\r\n各キャラクターを視覚的にユニークで表現力豊かに保ちながら、シーン全体でサイズ、フォーカス、パースペクティブのバランスをとる方法を学びます。 これは、アニメ風の物語のためのカバー、キャストラインナップ、またはプロモーションアートに取り組んで誰のための完璧なコースです。', 'Illustrating Anime Group Shots & Character Interactions', 'Draw group dynamics! Interactions, posing, and balance in multi-character scenes.', 'group shots, character interactions, dynamic poses', 'storage/photos/products/37.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Arrange multiple characters without visual chaos</li>\r\n  <li>Show relationships and tension through body language</li>\r\n  <li>Avoid stiffness in large group compositions</li>\r\n  <li>Use focal points and depth to guide the viewer\'s eye</li>\r\n  <li>Harmonize colors and lighting across multiple figures</li>\r\n</ul>', '<ul>\r\n  <li>視覚的な混乱なしに複数の文字を配置</li>\r\n  <li>ボディランゲージを通じて関係と緊張を示す</li>\r\n  <li>大規模なグループ組成物の剛性を避ける</li>\r\n  <li>焦点と深さを使用して視聴者の目を導く</li>\r\n  <li>複数の図形にわたって色と照明を調和させる</li>\r\n</ul>', 4, 0, 0, 4, 'Core Studio', 'コアスタジオ', 7, 'English & Japanese', '英語＆日本語', NULL, NULL),
(38, 'Poster Design and Visual Storytelling', 'ポスターデザインとビジュアルストーリーテリング', 'poster-design-and-visual-storytelling', '', '', 'An anime poster does more than look cool—it tells a story. This course dives into the techniques of visual storytelling through poster design, teaching you how to combine layout, character, environment, and type to capture your story’s soul in a single frame.\r\nYou’ll analyze examples from anime, games, and film while creating your own narrative-driven posters. Ideal for artists working on personal stories, campaigns, or fictional worlds.', 'アニメのポスターは、クールに見える以上のものです-それは物語を伝えます。 このコースでは、ポスターデザインを通じて視覚的なストーリーテリングのテクニックに飛び込み、レイアウト、キャラクター、環境、タイプを組み合わせて、ストーリーの魂を1つのフレームでキャプチャする方法を教えます。\r\nアニメ、ゲーム、映画の例を分析しながら、独自の物語主導のポスターを作成します。 個人的な物語、キャンペーン、または架空の世界に取り組んでいる芸術家のための理想。', 'Anime Poster Design: Visual Storytelling & Composition', 'Create eye-catching anime posters! Visual storytelling and composition tips.', 'poster design, composition, visual storytelling, anime art', 'storage/photos/products/38.webp', 10000, '', '', 'active', 49.00, 7840.00, 392.00, 0.00, 0, '<ul>\r\n  <li>Plan posters with a clear story and emotional hook</li>\r\n  <li>Integrate characters and backgrounds into a cohesive scene</li>\r\n  <li>Use color and negative space to control focus</li>\r\n  <li>Design for both visual impact and narrative clarity</li>\r\n  <li>Incorporate clean, stylized typography where needed</li>\r\n</ul>', '<ul>\r\n  <li>明確な物語と感情的なフックでポスターを計画</li>\r\n  <li>キャラクターと背景をまとまりのあるシーンに統合</li>\r\n  <li>色と負のスペースを使用してフォーカスを制御</li>\r\n  <li>視覚的なインパクトと物語の明快さの両方のためのデザイン</li>\r\n  <li>必要に応じてクリーンで様式化されたタイポグラフィを組み込む</li>\r\n</ul>', 4, 0, 0, 4, 'Narrative Art Series', 'ナラティブアートシリーズ', 8, 'English & Japanese', '英語＆日本語', NULL, NULL),
(42, 'Anime Portraits for Social Media and Commissions', 'ソーシャルメディアとコミッションのためのアニメの肖像画', 'anime-portraits-for-social-media-and-commissions', '', '', 'Stand out online and start earning through commissions. This course teaches how to craft eye-catching anime-style portraits that thrive on platforms like Instagram, Twitter, and DeviantArt. Focus on angles, expression, and background integration.', 'オンラインで目立つし、手数料を通じて収益を開始します。 このコースでは、Instagram、Twitter、DeviantArtなどのプラットフォームで繁栄する目を引くアニメスタイルの肖像画を作成する方法を教えます。instagram、Twitter、DeviantArtなどのプラットフォームで繁栄するアニメスタイルの肖像画。 角度、表現、および背景の統合に焦点を当てます。', 'Anime Portraits for Social Media & Commissions', 'Stunning anime portraits! Techniques for social media and commissions.', 'anime portraits, commissions, social media art', 'storage/photos/products/42.webp', 10000, '', '', 'active', 49.00, 7840.00, 392.00, 0.00, 0, '<ul>\r\n  <li>Design scroll-stopping portraits</li>\r\n  <li>Choose optimal canvas size and aspect ratio</li>\r\n  <li>Render eyes, hair, and skin with impact</li>\r\n  <li>Integrate soft backgrounds or patterns</li>\r\n  <li>Price and prep your work for commissions</li>\r\n</ul>', '<ul>\r\n  <li>デザインスクロール停止肖像画</li>\r\n  <li>最適なキャンバスサイズとアスペクト比を選択</li>\r\n  <li>目、髪、肌をインパクトでレンダリング</li>\r\n  <li>ソフトな背景やパターンを統合</li>\r\n  <li>価格と手数料のためのあなたの仕事を準備</li>\r\n</ul>', 4, 0, 0, 4, 'Freelance Studio', 'フリーランススタジオ', 8, 'English & Japanese', '英語＆日本語', NULL, NULL);
INSERT INTO `products` (`id`, `title`, `title_jp`, `slug`, `summary`, `summary_jp`, `description`, `description_jp`, `meta_title`, `meta_description`, `meta_keyword`, `photo`, `stock`, `size`, `condition`, `status`, `price`, `price_jp`, `price_hk`, `discount`, `is_featured`, `extra_description`, `extra_description_jp`, `cat_id`, `child_cat_id`, `brand_id`, `duration`, `skill_level`, `skill_level_jp`, `lectures`, `language`, `language_jp`, `created_at`, `updated_at`) VALUES
(45, 'Character Sprites for Visual Novels and JRPGs', 'ビジュアルノベルとJrpg用のキャラクタースプライト', 'character-sprites-for-visual-novels-and-jrpgs', '', '', 'Character sprites are the emotional core of anime games—your characters are the story. This course teaches you how to design clean, versatile sprites that can be used across visual novels, RPG dialogue scenes, and branching game narratives.\r\nYou’ll learn how to build consistent poses, design clothing that supports personality, and layer expressions or alternate outfits for flexible implementation. Whether your goal is a dating sim or a fantasy adventure, this course ensures your characters come alive on screen.', '「キャラクターのスプライトはアニメゲームの感情的なコアです-あなたのキャラクターは物語です。 このコースでは、ビジュアルノベル、RPG対話シーン、分岐ゲーム物語全体で使用できるクリーンで汎用性の高いスプライトを設計する方法を教えています。\r\n一貫性のあるポーズを構築し、個性をサポートする服をデザインし、柔軟な実装のための表現や代替衣装をレイヤー化する方法を学びます。 あなたの目標がデートシムであろうとファンタジーアドベンチャーであろうと、このコースはあなたのキャラクターが画面上で生き生きとしてくることを保証します。\"\"', 'Character Sprites for Visual Novels & JRPGs', 'Design character sprites for games! Expressions, poses, and animation prep.', 'character sprites, game art, visual novels, JRPGs', 'storage/photos/products/45.webp', 10000, '', '', 'active', 49.00, 7840.00, 392.00, 0.00, 0, '<ul>\r\n  <li>Design full-body or bust-up sprites for interactive games</li>\r\n  <li>Maintain consistency across emotion and pose sets</li>\r\n  <li>Optimize resolution, canvas size, and export formats</li>\r\n  <li>Build expression layers and variants efficiently</li>\r\n  <li>Create game-ready PNG sequences for plug-and-play use</li>\r\n</ul>', '<ul>\r\n  <li>インタラクティブゲーム用の全身またはバストアップスプライトをデザイン</li>\r\n  <li>感情とポーズのセット全体で一貫性を維持</li>\r\n  <li>解像度、キャンバスサイズ、およびエクスポート形式を最適化</li>\r\n  <li>エクスプレッションレイヤーとバリアントを効率的に構築</li>\r\n  <li>プラグアンドプレイ用のゲーム対応PNGシーケンスを作成</li>\r\n</ul>', 5, 0, 0, 4, 'Game Art Core', 'ゲームアートコア', 8, 'English & Japanese', '英語＆日本語', NULL, NULL),
(46, 'Creating Expression Sets for Dialogue Animation', '対話アニメーション用の式セットの作成', 'creating-expression-sets-for-dialogue-animation', '', '', 'This course focuses entirely on expressive storytelling through face and body language—one of the most crucial components in anime game narratives. You\'ll build a complete expression set for your character, suitable for visual novels and dialogue-heavy JRPGs.\r\nUsing pose libraries and reference breakdowns, you\'ll learn how to draw variations of eyes, eyebrows, mouths, and body tilts that can be layered and swapped for dynamic dialogue reactions.', '「このコースは、アニメゲームの物語の中で最も重要な要素の1つである、顔と体の言語による表現力豊かなストーリーテリングに完全に焦点を当てています。 あなたは、ビジュアルノベルや対話重いJrpgに適した、あなたのキャラクターのための完全な表現セットを構築します。\r\nポーズライブラリとリファレンスの内訳を使用して、目、眉毛、口、体の傾きのバリエーションを描画し、動的な対話反応のために階層化して交換する方法を学習します。\"\"', 'Expression Sets for Anime Dialogue & Animation', 'Create dialogue-ready expressions! Emotion sets for anime games/VNs.', 'expression sets, dialogue animation, emotion sprites', 'storage/photos/products/46.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Draw a wide range of anime facial expressions</li>\r\n  <li>Create swappable parts for modular character animation</li>\r\n  <li>Use subtle cues like eye position and tilt for emotion</li>\r\n  <li>Combine face and pose changes for nuanced reactions</li>\r\n  <li>Prepare sprites for Ren\'Py, Unity, and other engines</li>\r\n</ul>', '<ul>\r\n  <li>アニメの表情の広い範囲を描きます</li>\r\n  <li>モジュラーキャラクターアニメーション用のスワップ可能なパーツを作成</li>\r\n  <li>感情のために目の位置や傾きのような微妙な手がかりを使用してください</li>\r\n  <li>微妙な反応のために顔とポーズの変更を組み合わせる</li>\r\n  <li>Ren\'Py、Unity、およびその他のエンジン用のスプライトを準備</li>\r\n</ul>', 5, 0, 0, 4, 'Animation Lab', 'アニメーションラボ', 7, 'English & Japanese', '英語＆日本語', NULL, NULL),
(47, 'UI/UX Design for Anime Games: Menus, Stats, and More', 'アニメゲームのUI/UXデザイン：メニュー、統計など', 'ui-ux-design-for-anime-games-menus-stats-and-more', '', '', 'Menus aren’t just utility—they’re part of the game’s soul. This course explores how to design immersive, user-friendly UI/UX for anime games, covering everything from stat menus and inventories to dialogue boxes and loading screens.\r\nYou’ll balance functionality with anime aesthetics, crafting layouts that feel cohesive with your world’s tone while keeping the player experience intuitive and smooth.', '「メニューは単なるユーティリティではなく、ゲームの魂の一部です。 このコースでは、スタートメニューやインベントリからダイアログボックス、ロード画面まで、アニメゲームの没入型でユーザーフレンドリーなUI/UXを設計する方法\r\n機能性とアニメの美学のバランスをとり、プレイヤーの経験を直感的で滑らかに保ちながら、あなたの世界のトーンとまとまりを感じるレイアウトを作\"\"', 'UI/UX Design for Anime Games: Menus, Stats & More', 'UI/UX for anime games! Menus, HUDs, and stylish interfaces.', 'UI design, UX, game menus, anime interface', 'storage/photos/products/47.webp', 10000, '', '', 'active', 59.00, 9440.00, 472.00, 0.00, 0, '<ul>\r\n  <li>Design interface layouts with user flow in mind</li>\r\n  <li>Create stylized menus, buttons, and frames</li>\r\n  <li>Apply color, icons, and fonts for clarity and mood</li>\r\n  <li>Make HUDs for battle systems, inventories, and dialogue</li>\r\n  <li>Export UI assets optimized for Unity, Godot, and Ren\'Py</li>\r\n</ul>', '<ul>\r\n  <li>ユーザーの流れを念頭に置いたデザインインタフェースレイアウト</li>\r\n  <li>様式化されたメニュー、ボタン、およびフレームを作成</li>\r\n  <li>明瞭さと気分のために色、アイコン、フォントを適用</li>\r\n  <li>戦闘システム、在庫、対話のためのHudを作る</li>\r\n  <li>Unity、Godot、Ren\'Py用に最適化されたUIアセットをエクスポート</li>\r\n</ul>', 5, 0, 0, 5, 'Design Thinking Series', 'デザイン思考シリーズ', 9, 'English & Japanese', '英語＆日本語', NULL, NULL),
(48, 'Designing Game Assets: Tiles, Items, and Icons', 'ゲームアセットの設計：タイル、アイテム、アイコン', 'designing-game-assets-tiles-items-and-icons', '', '', 'From tiny potions to glowing treasure chests, every game asset adds flavor and functionality. This course teaches you how to design crisp, readable game items and tile-based environment components with a unique anime art style.\r\nYou’ll explore pixel art and high-res formats while building modular tilesets, decorative objects, and user-interface icons—perfect for top-down JRPGs, sims, or tactical games.', '\"\"小さなポーションから輝く宝箱まで、すべてのゲーム資産は味と機能を追加します。 このコースでは、ユニークなアニメアートスタイルで、鮮明で読みやすいゲームアイテムとタイルベースの環境コンポーネントを設計する方法を教えます。\r\nモジュラータイルセット、装飾オブジェクト、ユーザーインターフェイスのアイコンを構築しながら、ピクセルアートと高解像度のフォーマットを探索します。トップダウンのJrpg、シム、戦術的なゲームに最適です。\"\"', 'Designing Game Assets: Tiles, Items & Icons', 'Pixel art & game assets! Tiles, items, and icons for anime games.', 'game assets, tiles, icons, pixel art, anime items', 'storage/photos/products/48.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Create scalable environment tiles (grass, stone, buildings)</li>\r\n  <li>Design inventory icons with strong silhouettes</li>\r\n  <li>Match asset style with game resolution and camera angle</li>\r\n  <li>Work within constraints of pixel grids and tile systems</li>\r\n  <li>Export assets into game-ready spritesheets</li>\r\n</ul>', '<ul>\r\n  <li>スケーラブルな環境タイル（草、石、建物）を作成します</li>\r\n  <li>強いシルエットを持つデザインインベントリアイコン</li>\r\n  <li>ゲームの解像度とカメラアングルでアセットスタイルを一致させる</li>\r\n  <li>ピクセルグリッドとタイルシステムの制約内で動作</li>\r\n  <li>アセットをゲーム対応のスプライトシートにエクスポート</li>\r\n</ul>', 5, 0, 0, 4, 'Creative Production Series', '創作制作シリーズ', 7, 'English & Japanese', '英語＆日本語', NULL, NULL),
(49, 'Concept Art for Anime-Inspired Game Worlds', 'アニメにインスパイアされたゲームの世界のためのコンセプトアート', 'concept-art-for-anime-inspired-game-worlds', '', '', 'Every great game starts with a vision. In this course, you’ll learn how to create stunning environment concept art that defines the tone, setting, and exploration path of your game world—whether it\'s a floating sky kingdom, neon Tokyo street, or magical academy.\r\nThis course blends anime aesthetics with solid design foundations, helping you translate story lore into immersive visual worlds that feel rich and alive.', 'すべての偉大なゲームはビジョンから始まります。 このコースでは、フローティングスカイキングダム、ネオン東京ストリート、マジカルアカデミーなど、ゲームワールドのトーン、設定、探索パスを定義する見事な環境コンセプトアートを作成する方法を学びます。\r\nこのコースでは、アニメの美学と堅実なデザインの基礎を融合させ、ストーリーの伝承を豊かで生き生きとした没入型の視覚世界に翻訳するのに役立ちま', 'Concept Art for Anime Game Worlds: Design & Style', 'Concept art for game worlds! Anime-inspired environments and lore.', 'concept art, game worlds, anime inspiration, lore', 'storage/photos/products/49.webp', 10000, '', '', 'active', 49.00, 7840.00, 392.00, 0.00, 0, '<ul>\r\n  <li>Build moodboards and thumbnails for game worlds</li>\r\n  <li>Use perspective and scale to design immersive scenes</li>\r\n  <li>Concept cityscapes, dungeons, forests, or interiors</li>\r\n  <li>Show progression or lore through environmental details</li>\r\n  <li>Pitch-ready rendering techniques for portfolios or teams</li>\r\n</ul>', '<ul>\r\n  <li>ゲームの世界のためのムードボードとサムネイルを構築</li>\r\n  <li>遠近法とスケールを使用して没入型シーンを設計</li>\r\n  <li>コンセプト都市景観、ダンジョン、森林、またはインテリア</li>\r\n  <li>環境の詳細を通じて進行や伝承を表示</li>\r\n  <li>ポートフォリオやチームのためのピッチ対応レンダリング技術</li>\r\n</ul>', 5, 0, 0, 4, 'Concept Studio', 'コンセプトスタジオ', 8, 'English & Japanese', '英語＆日本語', NULL, NULL),
(50, 'Interactive Storyboarding for Visual Novels', 'ビジュアルノベルのためのインタラクティブストーリーボーディング', 'interactive-storyboarding-for-visual-novels', '', '', 'Plan out your branching narratives like a pro. This course teaches you how to storyboard interactive stories, mapping out player choices, camera angles, character positioning, and pacing for each scene.\r\nBy blending cinematic thinking with game logic, you\'ll create storyboards that keep players engaged and support meaningful decision-making. Perfect for solo creators and teams alike.', 'プロのようにあなたの分岐物語を計画します。 このコースでは、各シーンのプレイヤーの選択肢、カメラアングル、キャラクターの配置、ペーシングをマッピングし、インタラクティブなストーリーをストーリーボード\r\n映画的思考とゲームロジックを融合させることで、プレイヤーのエンゲージメントを維持し、意味のある意思決定をサポートするストーリーボードを作成できます。 ソロクリエイターやチームにも最適です。', 'Interactive Storyboarding for Visual Novels', 'Interactive storyboards for VNs! Planning choices, branches, and flow.', 'storyboarding, visual novels, branching, interactive', 'storage/photos/products/50.webp', 10000, '', '', 'active', 39.00, 6240.00, 312.00, 0.00, 0, '<ul>\r\n  <li>Break down scripts into dialogue and scene blocks</li>\r\n  <li>Visualize branching story paths and alternate outcomes</li>\r\n  <li>Place characters and camera dynamically in each scene</li>\r\n  <li>Use quick sketching and layout tools to plan visual flow</li>\r\n  <li>Prepare clean boards to guide game development</li>\r\n</ul>', '<ul>\r\n  <li>スクリプトを対話ブロックとシーンブロックに分解</li>\r\n  <li>分岐したストーリーパスと代替結果を視覚化</li>\r\n  <li>各シーンに文字とカメラを動的に配置</li>\r\n  <li>クイックスケッチとレイアウトツールを使用して視覚的な流れを計画</li>\r\n  <li>ゲーム開発を導くためにきれいなボードを準備</li>\r\n</ul>', 5, 0, 0, 4, 'Narrative Design Series', 'ナラティブデザインシリーズ', 7, 'English & Japanese', '英語＆日本語', NULL, NULL);

